const b = $input.first().json.body || {};
const clientId = (b.client_id || '').replace(/'/g, "''");
return [{
  json: {
    query: `SELECT id, token, primary_contact_name, primary_contact_phone, business_name FROM clients WHERE id = '${clientId}'`,
    client_id: b.client_id || '',
    agent_email: b.agent_email || '',
    html_body: b.html_body || ''
  }
}];

const lookup = $('Lookup Client').first().json;
const ctx = $('Build Lookup Query').first().json;

const prompt = 'Extract the following fields from this BoldTrail New Lead Notification HTML email.\nReturn valid JSON only. No explanation.\n\nFields:\n- lead_name (string)\n- phone (string, digits only, no formatting)\n- email (string)\n- property_interest (string — city, price, beds, baths as-is)\n- source (string)\n- referrer (string)\n- listing_url (string — the URL from the Notes field, or null if absent)\n\nHTML:\n' + ctx.html_body;

return [{
  json: {
    prompt,
    client_id: ctx.client_id,
    agent_email: ctx.agent_email,
    agent_name: lookup.primary_contact_name || '',
    agent_phone: lookup.primary_contact_phone || '',
    agent_token: lookup.token || '',
    brokerage: lookup.business_name || '',
    db_client_id: lookup.id || ctx.client_id
  }
}];

const response = $input.first().json;
const text = response.content[0].text.trim();
const ctx = $('Build Prompt').first().json;

let parsed;
try {
  const fenceMatch = text.match(/```(?:json)?\s*([\s\S]+?)```/);
  const objMatch = text.match(/(\{[\s\S]+\})/);
  parsed = JSON.parse(fenceMatch ? fenceMatch[1] : objMatch ? objMatch[1] : text);
} catch(e) {
  parsed = {};
}

return [{
  json: {
    lead_name: parsed.lead_name || '',
    phone: (parsed.phone || '').replace(/\D/g, ''),
    email: parsed.email || '',
    property_interest: parsed.property_interest || '',
    source: parsed.source || 'property_boost',
    referrer: parsed.referrer || '',
    listing_url: parsed.listing_url || null,
    client_id: ctx.client_id,
    agent_email: ctx.agent_email,
    agent_name: ctx.agent_name,
    agent_phone: ctx.agent_phone,
    brokerage: ctx.brokerage,
    db_client_id: ctx.db_client_id
  }
}];

const parsed = $('Parse Haiku Response').first().json;
let property_address = '';

try {
  const res = $input.first().json;
  const html = typeof res.data === 'string' ? res.data
             : typeof res.body === 'string' ? res.body
             : '';
  if (html) {
    const ldMatch = html.match(/<script type=["']?application\/ld\+json["']?>([\s\S]*?)<\/script>/);
    if (ldMatch) {
      const ld = JSON.parse(ldMatch[1]);
      const addr = ld.address || {};
      const candidate = [addr.streetAddress, addr.addressLocality, addr.addressRegion, addr.postalCode]
        .filter(Boolean).join(', ');
      if (/^\d/.test(candidate) && candidate.length > 8) {
        property_address = candidate;
      }
    }
  }
} catch(e) {
  property_address = '';
}

return [{ json: { ...parsed, property_address } }];

const d = $input.first().json;
const email = (d.email || '').trim().replace(/'/g, "''");
const phone = (d.phone || '').trim().replace(/'/g, "''");
const clientId = (d.db_client_id || '').replace(/'/g, "''");
// Only match on non-empty identity keys — a blank email/phone must never be a dedupe key,
// or it matches every existing lead with a blank value (false duplicate). Both blank => match nothing.
const orClauses = [];
if (email) orClauses.push(`email = '${email}'`);
if (phone) orClauses.push(`phone = '${phone}'`);
const matchClause = orClauses.length ? `(${orClauses.join(' OR ')})` : 'false';
return [{
  json: {
    query: `SELECT id FROM leads WHERE client_id = '${clientId}' AND ${matchClause} LIMIT 1`,
    ...d
  }
}];

const ctx = $('Build Dedupe Query').first().json;
const esc = v => (v || '').toString().replace(/'/g, "''");

const metadata = JSON.stringify({
  listing_url: ctx.listing_url || null,
  referrer: ctx.referrer || null,
  property_address: ctx.property_address || null
}).replace(/'/g, "''");

return [{
  json: {
    query: `INSERT INTO leads (client_id, lead_name, email, phone, source, lead_message, status, metadata) VALUES ('${esc(ctx.db_client_id)}', '${esc(ctx.lead_name)}', '${esc(ctx.email)}', '${esc(ctx.phone)}', 'property_boost', '${esc(ctx.property_interest)}', 'new', '${metadata}'::jsonb) RETURNING id`,
    ctx
  }
}];

const insertResult = $input.first().json;
const ctx = $('Build Dedupe Query').first().json;
const lookup = $('Lookup Client').first().json;

return [{
  json: {
    lead_id: insertResult.id,
    lead_name: ctx.lead_name,
    email: ctx.email,
    phone: ctx.phone,
    source: ctx.source || 'property_boost',
    lead_message: ctx.property_interest || 'PropertyBoost Facebook Lead Ad inquiry',
    property_address: ctx.property_address || '',
    agent_name: ctx.agent_name,
    agent_email: ctx.agent_email,
    agent_phone: ctx.agent_phone || '',
    agent_token: lookup.token || '',
    brokerage: ctx.brokerage || ''
  }
}];
